#include <bits/stdc++.h>
using namespace std;

bool balanced(const string& s) {
    stack<char> stk;
    for (char c : s) {
        if (c == '(' || c == '[' || c == '{') {
            stk.push(c);
        } else {
            if (stk.empty()) return false;
            char top = stk.top(); stk.pop();
            if (c == ')' && top != '(') return false;
            if (c == ']' && top != '[') return false;
            if (c == '}' && top != '{') return false;
        }
    }
    return stk.empty();
}

int main() {
    string s;
    cin >> s;
    cout << (balanced(s) ? "YES" : "NO") << "\n";
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;

    vector<int> nge(n, -1);   // next greater element, default -1
    stack<int> stk;           // stores INDICES, not values

    for (int i = 0; i < n; i++) {
        // pop indices whose values are smaller than arr[i]
        while (!stk.empty() && arr[stk.top()] < arr[i]) {
            nge[stk.top()] = arr[i];
            stk.pop();
        }
        stk.push(i);
    }
    // remaining elements have no next greater
    for (int i = 0; i < n; i++)
        cout << nge[i] << " ";
    cout << "\n";
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> h(n);
    for (int& x : h) cin >> x;

    stack<int> stk;   // increasing monotone stack of indices
    long long ans = 0;

    for (int i = 0; i <= n; i++) {
        int cur = (i == n) ? 0 : h[i];  // sentinel 0 at end flushes stack
        while (!stk.empty() && h[stk.top()] > cur) {
            int height = h[stk.top()]; stk.pop();
            int width = stk.empty() ? i : (i - stk.top() - 1);
            ans = max(ans, (long long)height * width);
        }
        stk.push(i);
    }
    cout << ans << "\n";
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int R, C;
    cin >> R >> C;
    vector<string> grid(R);
    for (auto& row : grid) cin >> row;

    // find start 'S' and end 'E'
    int sr, sc, er, ec;
    for (int i = 0; i < R; i++)
        for (int j = 0; j < C; j++) {
            if (grid[i][j] == 'S') { sr=i; sc=j; }
            if (grid[i][j] == 'E') { er=i; ec=j; }
        }

    vector<vector<int>> dist(R, vector<int>(C, -1));
    queue<pair<int,int>> q;
    dist[sr][sc] = 0;
    q.push({sr, sc});

    int dx[] = {0,0,1,-1};
    int dy[] = {1,-1,0,0};

    while (!q.empty()) {
        auto [r, c] = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = r + dx[d], nc = c + dy[d];
            if (nr>=0 && nr<R && nc>=0 && nc<C &&
                grid[nr][nc] != '#' && dist[nr][nc] == -1) {
                dist[nr][nc] = dist[r][c] + 1;
                q.push({nr, nc});
            }
        }
    }
    cout << dist[er][ec] << "\n";  // -1 if unreachable
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, k;
    cin >> n >> k;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;

    deque<int> dq;  // stores INDICES, maintained as decreasing-value deque
    vector<int> ans;

    for (int i = 0; i < n; i++) {
        // remove indices outside the window
        while (!dq.empty() && dq.front() <= i - k)
            dq.pop_front();

        // maintain decreasing order: remove indices with smaller values
        while (!dq.empty() && arr[dq.back()] <= arr[i])
            dq.pop_back();

        dq.push_back(i);

        // window is full starting from index k-1
        if (i >= k - 1)
            ans.push_back(arr[dq.front()]);
    }

    for (int x : ans) cout << x << " ";
    cout << "\n";
}

#include <bits/stdc++.h>
using namespace std;

const int INF = 1e9;

int main() {
    int n, m;
    cin >> n >> m;
    // adjacency list: {neighbor, weight (0 or 1)}
    vector<vector<pair<int,int>>> adj(n + 1);
    for (int i = 0; i < m; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w});
    }

    vector<int> dist(n + 1, INF);
    deque<int> dq;
    dist[1] = 0;
    dq.push_back(1);

    while (!dq.empty()) {
        int u = dq.front(); dq.pop_front();
        for (auto [v, w] : adj[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                if (w == 0) dq.push_front(v);   // 0-cost: front
                else        dq.push_back(v);    // 1-cost: back
            }
        }
    }

    for (int i = 1; i <= n; i++)
        cout << (dist[i] == INF ? -1 : dist[i]) << " ";
    cout << "\n";
}

