#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> temp(n);
    for (int& x : temp) cin >> x;

    vector<int> ans(n, 0);
    stack<int> stk;   // indices of unresolved days

    for (int i = 0; i < n; i++) {
        while (!stk.empty() && temp[stk.top()] < temp[i]) {
            ans[stk.top()] = i - stk.top();
            stk.pop();
        }
        stk.push(i);
    }
    // elements remaining in stack have ans=0 (already initialized)
    for (int x : ans) cout << x << " ";
    cout << "\n";
}

