#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> h(n);
    for (int& x : h) cin >> x;

    stack<int> stk;
    long long ans = 0;

    for (int i = 0; i <= n; i++) {
        int cur = (i == n) ? 0 : h[i];
        while (!stk.empty() && h[stk.top()] > cur) {
            int height = h[stk.top()]; stk.pop();
            // width: from stk.top()+1 to i-1
            int width = stk.empty() ? i : (i - stk.top() - 1);
            ans = max(ans, (long long)height * width);
        }
        stk.push(i);
    }
    cout << ans << "\n";
}

