// Given array of n integers and window size k,
// output the MINIMUM value in each window of size k.
// Constraints: n <= 2e5, k <= n, values in [-1e9, 1e9]
// Example: arr = [3, -1, -3, 5, 3, 6, 7], k = 3
// Output: [-1, -3, -3, 3, 3]

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, k;
    cin >> n >> k;
    vector<int> arr(n);
    for (int& x : arr) cin >> x;

    deque<int> dq;  // increasing monotone deque of indices
    vector<int> ans;

    for (int i = 0; i < n; i++) {
        // remove out-of-window indices from front
        if (!dq.empty() && dq.front() <= i - k)
            dq.pop_front();

        // maintain increasing order: pop back indices >= arr[i]
        while (!dq.empty() && arr[dq.back()] >= arr[i])
            dq.pop_back();

        dq.push_back(i);

        if (i >= k - 1)
            ans.push_back(arr[dq.front()]);
    }
    for (int x : ans) cout << x << " ";
    cout << "\n";
}
